import{_ as e,o as t,c as i,a2 as s}from"./chunks/framework.Bix3-HpO.js";const k=JSON.parse('{"title":"Plugin Blocks","description":"SpinokoGeo Plugin Blocks","frontmatter":{"title":"Plugin Blocks","description":"SpinokoGeo Plugin Blocks","weight":30,"extra":{"order":30},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/spinoko-geo/blocks"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/spinoko-geo/blocks"}],["meta",{"property":"og:title","content":"Plugin Blocks"}],["meta",{"property":"og:description","content":"SpinokoGeo Plugin Blocks"}],["meta",{"name":"twitter:title","content":"Plugin Blocks"}],["meta",{"name":"twitter:description","content":"SpinokoGeo Plugin Blocks"}]]},"headers":[],"relativePath":"docs/spinoko-geo/blocks.md","filePath":"docs/spinoko-geo/blocks.md"}'),n={name:"docs/spinoko-geo/blocks.md"};function a(l,o,c,r,p,g){return t(),i("div",null,[...o[0]||(o[0]=[s('<h1 id="plugin-blocks" tabindex="-1">Plugin Blocks <a class="header-anchor" href="#plugin-blocks" aria-label="Permalink to &quot;Plugin Blocks&quot;">​</a></h1><p>There are several blocks you can use to display your geo location based content on your website. Check them out below.</p><hr><h2 id="using-blocks" tabindex="-1">Using Blocks <a class="header-anchor" href="#using-blocks" aria-label="Permalink to &quot;Using Blocks&quot;">​</a></h2><p>Below are the blocks available in SpinokoGeo plugin:</p><ul><li>Geo Listing</li><li>Geo Content</li><li>Review Geo Message</li></ul><hr><h3 id="geo-listing-block" tabindex="-1">Geo Listing Block <a class="header-anchor" href="#geo-listing-block" aria-label="Permalink to &quot;Geo Listing Block&quot;">​</a></h3><p>To add a new listing simply click on the + (Add block) sign and select Geo Listing in Spinoko Blocks section.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko-geo/spinoko-geo-blocks--geo-listing.jpg" alt="SpinokoGeo Blocks - Geo Listing"></p><p>In the content editor a new listing edit section will appear. On the 1st tab you select the listing options such as listing type (grid, table, etc.), terms, whether to display filters, etc.</p><p>The 2nd tab, called Default, is where you select all the casinos that you want to display to users from countries that are not among your targeted ones.</p><p>After that there&#39;s a new tab for each country you target, simply add casinos or leave them empty to display the <strong>Default</strong> selection.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko-geo/spinoko-geo-blocks--geo-listing-manual.jpg" alt="SpinokoGeo Blocks - Geo Listing"></p><p>You can choose casinos manually, as shown in the image above, or filter them by category and/or tag. You can select a casino tag and all casinos with that tag will be displayed. You can also set a limit, for example, display all casinos in &quot;Poker&quot; category.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko-geo/spinoko-geo-blocks--geo-listing-tax.jpg" alt="SpinokoGeo Blocks - Geo Listing"></p><h3 id="geo-content-block" tabindex="-1">Geo Content Block <a class="header-anchor" href="#geo-content-block" aria-label="Permalink to &quot;Geo Content Block&quot;">​</a></h3><p>To add a new content block simply click on the + (Add block) sign and select Geo Content in Spinoko Blocks section.</p><p>In the content editor a new Content Block edit section will appear. Add your content to the rich-text editor and simply select the countries by toggling them on or off.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko-geo/spinoko-geo-blocks--geo-content.jpg" alt="SpinokoGeo Blocks - Geo Content"></p><h3 id="review-geo-message-block" tabindex="-1">Review Geo Message Block <a class="header-anchor" href="#review-geo-message-block" aria-label="Permalink to &quot;Review Geo Message Block&quot;">​</a></h3><p>To add a new message block simply click on the + (Add block) sign and select Review Geo Message in SpinokoGeo Blocks section.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko-geo/spinoko-geo-blocks--review-geo-message.jpg" alt="SpinokoGeo Blocks - Review Geo Message"></p><p>In the content editor a new message block edit section will appear. You can overwrite the default texts for messages for whether visitor&#39;s country is or isn&#39;t supported or keep the defaults.</p>',24)])])}const h=e(n,[["render",a]]);export{k as __pageData,h as default};
